import re


def has_main_guard(code_text):
    for line in code_text.splitlines():
        stripped = line.strip()
        if re.match(r'''if\s+__name__\s*==\s*['"]__main__['"]\s*:''', stripped):
            return True
    return False


def extract_main_block(code_text):
    lines = code_text.splitlines()
    in_block = False
    block_lines = []

    for line in lines:
        if in_block:
            if line.strip() == '' or (len(line) > 0 and line[0] in (' ', '\t')):
                block_lines.append(line)
            else:
                break
        else:
            stripped = line.strip()
            if re.match(r'''if\s+__name__\s*==\s*['"]__main__['"]\s*:''', stripped):
                in_block = True

    # Remove trailing empty lines
    while block_lines and block_lines[-1].strip() == '':
        block_lines.pop()

    return '\n'.join(block_lines)


def add_main_guard(code_text, main_func_name):
    if has_main_guard(code_text):
        return code_text
    guard = f"\n\nif __name__ == '__main__':\n    {main_func_name}()"
    return code_text + guard


def is_runnable_script(code_text):
    if not has_main_guard(code_text):
        return False

    main_block = extract_main_block(code_text)
    # Find function calls in the main block
    called_funcs = re.findall(r'\b([a-zA-Z_][a-zA-Z0-9_]*)\s*\(', main_block)

    # Find defined functions in the code
    defined_funcs = set()
    for line in code_text.splitlines():
        m = re.match(r'^def\s+([a-zA-Z_][a-zA-Z0-9_]*)\s*\(', line)
        if m:
            defined_funcs.add(m.group(1))

    # At least one called function must be defined
    return any(f in defined_funcs for f in called_funcs)
